import { ImageResponse } from "next/og";
import { NextRequest } from "next/server";

export const runtime = "edge";

// ─── Dimensões ────────────────────────────────────────────────────────────────
const W = 1080;
const H = 1350;

// ─── Paleta JORNAL (identidade Um País de Merda — estilo "imprensa") ──────────
const J_PAPER = "#ece3d0";   // papel envelhecido
const J_INK   = "#171511";   // tinta
const J_RUST  = "#a83f30";   // carimbo / acento
const J_GOLD  = "#b8902a";   // acento secundário
const J_MUTED = "#6f6857";   // dateline / rodapé

// ─── Proporções: site usa aspect-square para o PosterFace ────────────────────
// Card width = W - 2*CM. PosterFace é quadrado = CW × CW. Caption bar abaixo.
const CM = 44;          // margem frame → cartão
const CW = W - CM * 2; // 992px — largura do cartão
// O cartão tem: poster quadrado (992×992) + caption bar (88px) = 1080px total
// Mas nosso frame é 1350px, então temos 270px extras distribuídos acima/abaixo do card
const CAPTION_H = 88;
const CH = CW + CAPTION_H;  // 1080px total do cartão (poster 992² + caption 88)

// ─── Escala: site original ~394px → nosso ~992px → factor ≈ 2.52 ───────────
const F = CW / 394; // ≈ 2.52

// Padding interno: p-7 = 28px original → ~71px
const PAD = Math.round(28 * F);

// ─── Carregar fonte Fraunces ──────────────────────────────────────────────────
// P052-Bold (OTF serif — Satori-compatible) embedded
const FONT_B64 = "";

async function loadFraunces(): Promise<ArrayBuffer> {
  // Fonte Fraunces 700 com glifos LATIN-EXT (inclui acentos do PT em caixa-alta:
  // Ã Õ Ê Ô Ç Á É Í Ó Ú). Arquivo colocado ao lado da rota. Substitui o subset
  // base64 herdado do DR (espanhol), que faltava os acentos do português.
  return fetch(new URL("./Fraunces.ttf", import.meta.url)).then((r) => r.arrayBuffer());
}

// ─── Tamanho da fonte do título ───────────────────────────────────────────────
const SERIF = '"Fraunces", ui-serif, Georgia, serif';

function titleSize(text: string): number {
  const l = text.length;
  if (l <= 14) return 150;
  if (l <= 22) return 128;
  if (l <= 32) return 108;
  if (l <= 44) return 92;
  if (l <= 58) return 78;
  if (l <= 76) return 64;
  return 54;
}

// Garante que o título caiba na largura: limita pela palavra MAIS LONGA
// (Fraunces 700 em caixa-alta ≈ 0.66·fontSize por caractere). Evita corte.
function fitTitleSize(text: string, maxWidth: number): number {
  const base = titleSize(text);
  const longest = text.split(/\s+/).reduce((m, w) => Math.max(m, w.length), 0);
  const byWord = Math.floor(maxWidth / Math.max(longest, 1) / 0.66);
  return Math.max(40, Math.min(base, byWord));
}

// RNG determinístico por post: mesmo seed → mesmo desenho (estável entre renders)
function hashStr(s: string): number {
  let h = 2166136261;
  for (let i = 0; i < s.length; i++) { h ^= s.charCodeAt(i); h = Math.imul(h, 16777619); }
  return h >>> 0;
}

// ─── Direção de arte por tema (sem IA: cor de tinta + motivo procedural) ──────

type Cat = "freedom" | "self" | "network" | "dopamine" | "anxiety" | "mind";

// 21 motivos distintos — um por TEMA (não por categoria). A cor segue a
// categoria (coesão de marca); o DESENHO é único por tema.
type MotifId =
  | "gateway" | "iris" | "web" | "spiral" | "burst" | "branches"
  | "waves" | "bars" | "isolation" | "ripple" | "descent" | "boundary"
  | "clock" | "synapse" | "squares" | "orbit" | "decay" | "masks"
  | "unplug" | "embrace" | "mirror";

const MOTIF_IDS: readonly MotifId[] = [
  "gateway", "iris", "web", "spiral", "burst", "branches",
  "waves", "bars", "isolation", "ripple", "descent", "boundary",
  "clock", "synapse", "squares", "orbit", "decay", "masks",
  "unplug", "embrace", "mirror",
];

interface CatStyle { accent: string; label: string }

const CATS: Record<Cat, CatStyle> = {
  freedom:  { accent: "#A45A5A", label: "LIBERTAD"   },
  dopamine: { accent: "#BE7A2A", label: "RECOMPENSA" },
  anxiety:  { accent: "#3D6360", label: "ANSIEDAD"   },
  network:  { accent: "#3F5E78", label: "CONEXIÓN"   },
  self:     { accent: "#835A6E", label: "EL YO"      },
  mind:     { accent: "#5B6B3C", label: "LA MENTE"   },
};

// ─── i18n do criativo (ES default / PT-BR) ───────────────────────────────────
// Mantém o /api/og autossuficiente (edge): sem importar de @/lib/accounts.
type OgLang = "es" | "pt";

// Rótulo da categoria → pilar editorial (rodapé do criativo). Mapa cat→pilar é a
// FONTE ÚNICA em publish/route.ts (THEMES). Mantém ES e PT iguais (conta PT-only).
const CAT_LABEL: Record<OgLang, Record<Cat, string>> = {
  es: { freedom: "LIBERDADE", dopamine: "PÃO E CIRCO", anxiety: "O ESTADO", network: "A CASTA", self: "O SERVO", mind: "O DESPERTAR" },
  pt: { freedom: "LIBERDADE", dopamine: "PÃO E CIRCO", anxiety: "O ESTADO", network: "A CASTA", self: "O SERVO", mind: "O DESPERTAR" },
};

// Motivo padrão por categoria (fallback quando ?motif= não vem)
const CAT_DEFAULT_MOTIF: Record<Cat, MotifId> = {
  freedom: "gateway", dopamine: "burst", anxiety: "waves",
  network: "web", self: "masks", mind: "synapse",
};

// Deriva a categoria a partir do tópico/keyword (heurística por palavras-chave)
function detectCat(s: string): Cat {
  const t = (s || "").toLowerCase();
  if (/dopamin|recompens|validac|aplauso|like|adicc|desintox|casino|tragamoned|tel[eé]fono|atenci|pantalla|trafican/.test(t)) return "dopamine";
  if (/ansied|miedo|fracaso|perfeccion|burnout|procrastin|culpa|paraliz|estr[eé]s|sabote/.test(t)) return "anxiety";
  if (/red|social|comparaci|soledad|amigo|conect|relacion/.test(t)) return "network";
  if (/ego|m[aá]scar|autoconoc|amor propio|autoexig|l[ií]mite|yo real|espejo|conscien/.test(t)) return "self";
  if (/mente|neuroplast|aburr|cambiar|cerebro|reprogram/.test(t)) return "mind";
  if (/libert|elecc|elegir|decis/.test(t)) return "freedom";
  return "freedom";
}

// ─── CAPA estilo JORNAL (identidade Um País de Merda) ─────────────────────────
// Autossuficiente (não usa moldura compartilhada). Papel + tinta + carimbo vermelho + dateline.
function JornalCover({ title, label, issueNo, stamp, dateline }: {
  title: string; label: string; issueNo: string; stamp: string; dateline: string;
}) {
  const PADW = 28 + 3 + 48; // margem + borda + padding internos (por lado)
  const headSize = fitTitleSize(title, W - 2 * PADW);
  return (
    <div style={{ width: W, height: H, display: "flex", background: J_PAPER, padding: 28 }}>
      <div style={{
        position: "relative", display: "flex", flexDirection: "column",
        width: "100%", height: "100%", border: `3px solid ${J_INK}`, padding: 48, color: J_INK,
      }}>
        {/* masthead */}
        <div style={{ display: "flex", flexDirection: "column", flexShrink: 0 }}>
          <div style={{ display: "flex", justifyContent: "space-between", alignItems: "baseline" }}>
            <span style={{ fontFamily: SERIF, fontWeight: 700, fontSize: 56, letterSpacing: "-0.02em", color: J_INK }}>UM PAÍS DE MERDA</span>
            <span style={{ fontFamily: SERIF, fontSize: 30, letterSpacing: "0.10em", color: J_RUST }}>{issueNo}</span>
          </div>
          <div style={{ marginTop: 14, height: 4, width: "100%", background: J_INK, display: "flex" }} />
          <span style={{ fontFamily: SERIF, fontSize: 21, letterSpacing: "0.22em", color: J_MUTED, marginTop: 12, textTransform: "uppercase" }}>{dateline}</span>
        </div>

        {/* kicker */}
        <div style={{ display: "flex", justifyContent: "space-between", alignItems: "center", marginTop: 30, flexShrink: 0 }}>
          <span style={{ fontFamily: SERIF, fontSize: 24, letterSpacing: "0.20em", color: J_RUST, textTransform: "uppercase" }}>{label}</span>
          <span style={{ fontFamily: SERIF, fontSize: 22, letterSpacing: "0.24em", color: J_MUTED }}>CAPA</span>
        </div>

        {/* manchete — caixa-alta via CSS (satori); NUNCA .toUpperCase() no JS:
            no edge runtime o toUpperCase quebra acentos do PT (vira tofu). */}
        <div style={{ flex: 1, display: "flex", flexDirection: "column", justifyContent: "center" }}>
          <span style={{ fontFamily: SERIF, fontWeight: 700, fontSize: headSize, lineHeight: 0.95, letterSpacing: "-0.03em", color: J_INK, maxWidth: W - 2 * PADW, textTransform: "uppercase" }}>
            {title}
          </span>
        </div>

        {/* carimbo */}
        {stamp ? (
          <div style={{
            position: "absolute", top: 430, right: 18, display: "flex",
            transform: "rotate(-8deg)", border: `4px solid ${J_RUST}`,
            padding: "8px 16px", opacity: 0.86,
          }}>
            <span style={{ fontFamily: SERIF, fontSize: 30, letterSpacing: "0.04em", color: J_RUST, textTransform: "uppercase" }}>{stamp}</span>
          </div>
        ) : null}

        {/* rodapé */}
        <div style={{ display: "flex", justifyContent: "space-between", alignItems: "center", borderTop: `2px solid ${J_INK}`, paddingTop: 16, flexShrink: 0 }}>
          <span style={{ fontFamily: SERIF, fontSize: 24, color: J_INK }}>@umpaisdemerda</span>
          <span style={{ fontFamily: SERIF, fontSize: 22, letterSpacing: "0.10em", color: J_MUTED }}>vire →</span>
        </div>
      </div>
    </div>
  );
}

function toRoman(n: number): string {
  return ["", "i", "ii", "iii", "iv", "v", "vi", "vii", "viii"][n] ?? String(n);
}

// ─── Moldura jornal compartilhada (masthead + kicker + rodapé) ────────────────
function JornalFrame({ dark, issueNo, kicker, page, footLeft, footRight, dateline, children }: {
  dark?: boolean; issueNo: string; kicker: string; page: string;
  footLeft: string; footRight: string; dateline?: string; children: React.ReactNode;
}) {
  const paper = dark ? J_INK : J_PAPER;
  const ink   = dark ? J_PAPER : J_INK;
  const muted = dark ? "#9c9686" : J_MUTED;
  const accent = dark ? J_GOLD : J_RUST;
  return (
    <div style={{ width: W, height: H, display: "flex", background: paper, padding: 28 }}>
      <div style={{ position: "relative", display: "flex", flexDirection: "column", width: "100%", height: "100%", border: `3px solid ${ink}`, padding: 48, color: ink }}>
        <div style={{ display: "flex", flexDirection: "column", flexShrink: 0 }}>
          <div style={{ display: "flex", justifyContent: "space-between", alignItems: "baseline" }}>
            <span style={{ fontFamily: SERIF, fontWeight: 700, fontSize: 56, letterSpacing: "-0.02em", color: ink }}>UM PAÍS DE MERDA</span>
            <span style={{ fontFamily: SERIF, fontSize: 30, letterSpacing: "0.10em", color: accent }}>{issueNo}</span>
          </div>
          <div style={{ marginTop: 14, height: 4, width: "100%", background: ink, display: "flex" }} />
          {dateline ? <span style={{ fontFamily: SERIF, fontSize: 21, letterSpacing: "0.22em", color: muted, marginTop: 12, textTransform: "uppercase" }}>{dateline}</span> : null}
        </div>
        <div style={{ display: "flex", justifyContent: "space-between", alignItems: "center", marginTop: 30, flexShrink: 0 }}>
          <span style={{ fontFamily: SERIF, fontSize: 24, letterSpacing: "0.20em", color: accent, textTransform: "uppercase" }}>{kicker}</span>
          <span style={{ fontFamily: SERIF, fontSize: 22, letterSpacing: "0.24em", color: muted, textTransform: "uppercase" }}>{page}</span>
        </div>
        {children}
        <div style={{ display: "flex", justifyContent: "space-between", alignItems: "center", borderTop: `2px solid ${ink}`, paddingTop: 16, flexShrink: 0 }}>
          <span style={{ fontFamily: SERIF, fontSize: 24, color: dark ? J_GOLD : J_INK }}>{footLeft}</span>
          <span style={{ fontFamily: SERIF, fontSize: 22, letterSpacing: "0.10em", color: muted }}>{footRight}</span>
        </div>
      </div>
    </div>
  );
}

// ─── SLIDE insight (jornal): numeral romano + pull-quote (caixa mista) ────────
function JornalInsight({ text, num, total, label, issueNo }: {
  text: string; num: number; total: number; label: string; issueNo: string;
}) {
  const isSave = num === total - 1; // último insight = o "salvável"
  const size = Math.min(fitTitleSize(text, 922), 74);
  return (
    <JornalFrame issueNo={issueNo} kicker={label} page={`${num} / ${total}`} footLeft="@umpaisdemerda" footRight="vire →">
      <div style={{ flex: 1, display: "flex", flexDirection: "column", justifyContent: "center" }}>
        <span style={{ fontFamily: SERIF, fontStyle: "italic", fontSize: 56, color: J_RUST, marginBottom: 6 }}>{toRoman(num - 1)}.</span>
        <span style={{ fontFamily: SERIF, fontWeight: 700, fontSize: size, lineHeight: 1.07, letterSpacing: "-0.01em", color: J_INK, maxWidth: 922 }}>{text}</span>
        {isSave ? (
          <div style={{ display: "flex", marginTop: 28, border: `2px solid ${J_RUST}`, padding: "8px 16px", alignSelf: "flex-start" }}>
            <span style={{ fontFamily: SERIF, fontSize: 22, letterSpacing: "0.12em", color: J_RUST, textTransform: "uppercase" }}>salve esta</span>
          </div>
        ) : null}
      </div>
    </JornalFrame>
  );
}

// ─── SLIDE CTA (jornal): invertido (tinta/papel) + "a pergunta da edição" ─────
function JornalCTA({ text, total, label, issueNo }: {
  text: string; total: number; label: string; issueNo: string;
}) {
  const size = Math.min(fitTitleSize(text, 922), 70);
  return (
    <JornalFrame dark issueNo={issueNo} kicker={label} page={`${total} / ${total}`} footLeft="siga @umpaisdemerda" footRight="responda aí ↓">
      <div style={{ flex: 1, display: "flex", flexDirection: "column", justifyContent: "center" }}>
        <span style={{ fontFamily: SERIF, fontSize: 24, letterSpacing: "0.24em", color: J_GOLD, marginBottom: 22, textTransform: "uppercase" }}>A pergunta da edição</span>
        <span style={{ fontFamily: SERIF, fontWeight: 700, fontSize: size, lineHeight: 1.06, letterSpacing: "-0.01em", color: J_PAPER, maxWidth: 922 }}>{text}</span>
      </div>
    </JornalFrame>
  );
}

// ─── OVERLAY de REEL (9:16, fundo TRANSPARENTE) p/ compor sobre footage no ffmpeg ─
// Renderiza barra (masthead), kicker, manchete (com destaque opcional) e rodapé,
// sobre um scrim escuro semi-transparente (legibilidade) — o vídeo aparece atrás.
function JornalReel({ RW, RH, issueNo, kicker, title, hl, foot, fam, hlmode }: {
  RW: number; RH: number; issueNo: string; kicker: string; title: string; hl: string; foot: string;
  fam: string; hlmode: string;
}) {
  const size = Math.min(fitTitleSize(title, RW - 112), 116);
  const hlSize = Math.round(size * 0.94);
  // destaque limpo (sem caixa "clunky"): dourado puro · barra inferior · sublinhado grosso
  const hlNode = !hl ? null
    : hlmode === "bar" ? (
      <div style={{ display: "flex", marginTop: 18, background: J_INK, padding: "10px 18px", alignSelf: "flex-start" }}>
        <span style={{ fontFamily: fam, fontSize: hlSize, lineHeight: 1.0, color: J_GOLD, textTransform: "uppercase", maxWidth: RW - 152 }}>{hl}</span>
      </div>
    ) : hlmode === "under" ? (
      <div style={{ display: "flex", marginTop: 14, borderBottom: `10px solid ${J_GOLD}`, paddingBottom: 4, alignSelf: "flex-start" }}>
        <span style={{ fontFamily: fam, fontSize: hlSize, lineHeight: 1.0, color: J_PAPER, textTransform: "uppercase", maxWidth: RW - 112 }}>{hl}</span>
      </div>
    ) : (
      <span style={{ fontFamily: fam, fontSize: hlSize, lineHeight: 1.02, color: J_GOLD, textTransform: "uppercase", marginTop: 10, maxWidth: RW - 112, display: "flex" }}>{hl}</span>
    );
  return (
    <div style={{ width: RW, height: RH, display: "flex", flexDirection: "column", position: "relative", padding: 56 }}>
      <div style={{ position: "absolute", top: 0, left: 0, width: RW, height: RH, display: "flex",
        background: "linear-gradient(180deg, rgba(20,18,13,0.62) 0%, rgba(20,18,13,0.16) 30%, rgba(20,18,13,0.92) 80%)" }} />
      <div style={{ position: "relative", display: "flex", justifyContent: "space-between", alignItems: "center", borderBottom: "2px solid rgba(236,227,208,0.55)", paddingBottom: 14 }}>
        <span style={{ fontFamily: SERIF, fontWeight: 700, fontSize: 40, letterSpacing: "-0.02em", color: J_PAPER }}>UM PAÍS DE MERDA</span>
        <span style={{ fontFamily: SERIF, fontSize: 26, letterSpacing: "0.10em", color: J_GOLD }}>{issueNo} · REEL</span>
      </div>
      <div style={{ position: "relative", flex: 1, display: "flex", flexDirection: "column", justifyContent: "flex-end" }}>
        {kicker ? <span style={{ fontFamily: fam, fontSize: 30, letterSpacing: "0.14em", color: J_GOLD, marginBottom: 20, textTransform: "uppercase", display: "flex" }}>{kicker}</span> : null}
        <span style={{ fontFamily: fam, fontSize: size, lineHeight: 1.0, color: J_PAPER, textTransform: "uppercase", maxWidth: RW - 112, display: "flex" }}>{title}</span>
        {hlNode}
      </div>
      <div style={{ position: "relative", display: "flex", justifyContent: "space-between", alignItems: "center", marginTop: 28 }}>
        <span style={{ fontFamily: SERIF, fontSize: 30, color: J_PAPER }}>@umpaisdemerda</span>
        <span style={{ fontFamily: SERIF, fontSize: 26, letterSpacing: "0.08em", color: "#cdbfa2" }}>{foot}</span>
      </div>
    </div>
  );
}

// ─── Handler principal ────────────────────────────────────────────────────────
export async function GET(req: NextRequest) {
  try {
    const { searchParams } = req.nextUrl;
    const slide = searchParams.get("slide") ?? "cover";
    const title = searchParams.get("title") ?? "A nação de servos voluntários";
    const text  = searchParams.get("text")  ?? "";
    const kw    = searchParams.get("kw")    ?? "";
    const tag   = searchParams.get("tag")   ?? "";
    const issue = `ED. ${searchParams.get("ed") ?? "01"}`;
    const mood  = (searchParams.get("mood") ?? "red") as "red" | "ink";
    const num   = parseInt(searchParams.get("num")   ?? "2");
    const total = parseInt(searchParams.get("total") ?? "5");
    const lang: OgLang = searchParams.get("lang") === "es" ? "es" : "pt";

    // Categoria (direção de arte): vem de ?cat= ou é derivada do tema
    const catParam = searchParams.get("cat");
    const cat: Cat = catParam && (catParam in CATS) ? (catParam as Cat) : detectCat(`${title} ${text} ${kw} ${tag}`);

    // Motivo (desenho) por TEMA: vem de ?motif= ou cai no padrão da categoria
    const motifParam = searchParams.get("motif");
    const motif: MotifId = motifParam && (MOTIF_IDS as readonly string[]).includes(motifParam)
      ? (motifParam as MotifId)
      : CAT_DEFAULT_MOTIF[cat];

    // Seed estável por POST (mesmo em todas as slides do carrossel) → desenho único
    const seedParam = searchParams.get("seed");
    const seed = seedParam ? hashStr(seedParam) : hashStr(`${issue}|${kw}|${cat}|${motif}`);

    const fontBold = await loadFraunces();

    const issueNo  = issue.replace(/^ED\.\s*/i, "Nº ");
    const kicker   = CAT_LABEL[lang][cat];

    let node;
    let RW = W, RH = H;
    let reelFont: { name: string; file: string; weight: 400 | 700 } | null = null;
    if (slide === "reel") {
      RW = 1080; RH = 1920;
      const hl   = searchParams.get("hl") ?? "";
      const kick = searchParams.get("kicker") ?? "";
      const foot = searchParams.get("foot") ?? "siga ↑";
      const variant = (searchParams.get("variant") ?? "A").toUpperCase();
      const VMAP: Record<string, { name: string; file: string; weight: 400 | 700; hl: string }> = {
        A: { name: "Anton",        file: "./Anton.ttf",        weight: 400, hl: "gold" },
        B: { name: "ArchivoBlack", file: "./ArchivoBlack.ttf", weight: 400, hl: "bar" },
        C: { name: "Oswald",       file: "./Oswald.ttf",       weight: 700, hl: "under" },
      };
      const v = VMAP[variant] ?? VMAP.A;
      reelFont = { name: v.name, file: v.file, weight: v.weight };
      const hlmode = searchParams.get("hlmode") ?? v.hl;
      const fam = `"${v.name}", sans-serif`;
      node = <JornalReel RW={RW} RH={RH} issueNo={issueNo} kicker={kick} title={title} hl={hl} foot={foot} fam={fam} hlmode={hlmode} />;
    } else if (slide === "cta") {
      node = <JornalCTA text={text || title} total={total} label={kicker} issueNo={issueNo} />;
    } else if (slide === "insight") {
      node = <JornalInsight text={text} num={num} total={total} label={kicker} issueNo={issueNo} />;
    } else {
      const stamp    = searchParams.get("stamp") ?? "";
      const dateline = searchParams.get("dateline") ?? "Brasil · ano 525 da servidão voluntária";
      node = <JornalCover title={title} label={kicker} issueNo={issueNo} stamp={stamp} dateline={dateline} />;
    }

    const fonts: { name: string; data: ArrayBuffer; weight: 400 | 700; style: "normal" }[] =
      [{ name: "Fraunces", data: fontBold, weight: 700, style: "normal" }];
    if (reelFont) {
      const data = await fetch(new URL(reelFont.file, import.meta.url)).then((r) => r.arrayBuffer());
      fonts.push({ name: reelFont.name, data, weight: reelFont.weight, style: "normal" });
    }

    return new ImageResponse(node, {
      width: RW,
      height: RH,
      fonts,
      // og é determinístico por URL → o Instagram pode reusar o fetch (e reduz cold starts).
      headers: { "cache-control": "public, max-age=86400, s-maxage=86400, immutable" },
    });
  } catch (err: unknown) {
    const msg = err instanceof Error ? err.message : String(err);
    return new Response(`OG Error: ${msg}`, { status: 500 });
  }
}
